// ─── SIGNUP / WAITLIST ───
function Signup() {
  const [form, setForm] = useState({
    name: "",
    email: "",
    product: "",
    experience: "",
    message: "",
  });
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [focused, setFocused] = useState("");

  const products = [
    {
      value: "Toji Physique Protocol (6-Day, 4-Week)",
      label: "Toji Physique Protocol — 6-Day, 4-Week",
      tag: "AVAILABLE SOON",
    },
    { value: "3-Day Plan", label: "3-Day Plan", tag: "COMING SOON" },
    { value: "4-Day Plan", label: "4-Day Plan", tag: "COMING SOON" },
    { value: "5-Day Plan", label: "5-Day Plan", tag: "COMING SOON" },
    {
      value: "Custom / Not sure yet",
      label: "Not sure — help me choose",
      tag: "GUIDANCE",
    },
  ];

  const experiences = [
    "Beginner (< 1 year)",
    "Intermediate (1-3 years)",
    "Advanced (3+ years)",
  ];

  const update = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
    if (error) setError("");
  };

  const handleSubmit = async () => {
    if (!form.email || !form.email.includes("@") || form.email.length < 5) {
      setError("Please enter a valid email address.");
      return;
    }
    if (!form.product) {
      setError("Please select a program you're interested in.");
      return;
    }
    setError("");
    setLoading(true);

    try {
      const response = await fetch(
        "https://formsubmit.co/ajax/Ahaniramtin@gmail.com",
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Accept: "application/json",
          },
          body: JSON.stringify({
            Name: form.name || "Not provided",
            Email: form.email,
            Product_Interest: form.product,
            Experience_Level: form.experience || "Not specified",
            Message: form.message || "No additional notes",
            _subject: `🔥 New Waitlist Signup — ${form.product}`,
            _template: "table",
            _captcha: "false",
            _autoresponse:
              "Thanks for joining the Lets.getJacked waitlist! We received your interest and will reach out with next steps soon. Follow @letsgocosplay on YouTube in the meantime. — Ramtin",
          }),
        }
      );
      if (response.ok) {
        setSubmitted(true);
      } else {
        setError("Submission failed. Please try again in a moment.");
      }
    } catch (e) {
      setError("Network error. Please check your connection and try again.");
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = (field) => ({
    width: "100%",
    padding: "13px 16px",
    background: "rgba(255,255,255,0.03)",
    border: `1px solid ${focused === field ? T.purple : T.border}`,
    borderRadius: 2,
    color: T.white,
    fontSize: 14,
    fontFamily: "'Outfit',sans-serif",
    transition: "all 0.3s",
    boxShadow: focused === field ? `0 0 0 3px rgba(139,92,246,0.08)` : "none",
  });

  return (
    <Section id="signup" bg={T.bgSection}>
      <GlowOrb
        color={T.purple}
        size={500}
        top="-20%"
        left="10%"
        opacity={0.08}
      />
      <GlowOrb
        color={T.blue}
        size={400}
        bottom="-10%"
        right="10%"
        opacity={0.05}
      />
      <div style={{ maxWidth: 620, margin: "0 auto" }}>
        <Heading
          tag="Early Access"
          title={
            <>
              JOIN THE <span style={{ color: T.purple }}>WAITLIST</span>
            </>
          }
          subtitle="Pick the program you're interested in. Drop your email. I'll personally reach out with next steps and early access when it drops."
        />

        {!submitted ? (
          <div
            style={{
              background: T.bgCard,
              border: `1px solid ${T.border}`,
              borderRadius: 4,
              padding: "36px 32px",
              boxShadow: `0 12px 48px rgba(0,0,0,0.4), 0 0 40px ${T.purpleGlow}`,
            }}
          >
            {/* Name */}
            <div style={{ marginBottom: 18 }}>
              <label
                style={{
                  display: "block",
                  fontSize: 10,
                  letterSpacing: 2,
                  textTransform: "uppercase",
                  color: T.muted,
                  marginBottom: 8,
                }}
              >
                Name{" "}
                <span style={{ color: T.muted, opacity: 0.5 }}>(optional)</span>
              </label>
              <input
                type="text"
                placeholder="Your name"
                value={form.name}
                onChange={(e) => update("name", e.target.value)}
                onFocus={() => setFocused("name")}
                onBlur={() => setFocused("")}
                style={inputStyle("name")}
              />
            </div>

            {/* Email */}
            <div style={{ marginBottom: 18 }}>
              <label
                style={{
                  display: "block",
                  fontSize: 10,
                  letterSpacing: 2,
                  textTransform: "uppercase",
                  color: T.muted,
                  marginBottom: 8,
                }}
              >
                Email <span style={{ color: T.purple }}>*</span>
              </label>
              <input
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={(e) => update("email", e.target.value)}
                onFocus={() => setFocused("email")}
                onBlur={() => setFocused("")}
                style={inputStyle("email")}
                required
              />
            </div>

            {/* Product selector */}
            <div style={{ marginBottom: 18 }}>
              <label
                style={{
                  display: "block",
                  fontSize: 10,
                  letterSpacing: 2,
                  textTransform: "uppercase",
                  color: T.muted,
                  marginBottom: 10,
                }}
              >
                Which program? <span style={{ color: T.purple }}>*</span>
              </label>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {products.map((p) => {
                  const selected = form.product === p.value;
                  return (
                    <button
                      key={p.value}
                      type="button"
                      onClick={() => update("product", p.value)}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-between",
                        padding: "13px 16px",
                        background: selected
                          ? "rgba(139,92,246,0.08)"
                          : "rgba(255,255,255,0.02)",
                        border: `1px solid ${selected ? T.purple : T.border}`,
                        borderRadius: 2,
                        color: T.white,
                        cursor: "pointer",
                        textAlign: "left",
                        fontFamily: "'Outfit',sans-serif",
                        fontSize: 13,
                        transition: "all 0.25s ease",
                      }}
                    >
                      <span
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: 12,
                        }}
                      >
                        <span
                          style={{
                            width: 14,
                            height: 14,
                            borderRadius: "50%",
                            border: `1px solid ${
                              selected ? T.purple : T.muted
                            }`,
                            background: selected ? T.purple : "transparent",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            flexShrink: 0,
                            boxShadow: selected
                              ? `0 0 8px ${T.purpleGlow}`
                              : "none",
                          }}
                        >
                          {selected && (
                            <span
                              style={{
                                width: 5,
                                height: 5,
                                borderRadius: "50%",
                                background: "#fff",
                              }}
                            />
                          )}
                        </span>
                        <span>{p.label}</span>
                      </span>
                      <span
                        style={{
                          fontSize: 9,
                          letterSpacing: 1.5,
                          color: selected ? T.purple : T.muted,
                          padding: "3px 8px",
                          border: `1px solid ${
                            selected ? T.borderHover : T.border
                          }`,
                          borderRadius: 2,
                        }}
                      >
                        {p.tag}
                      </span>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Experience level */}
            <div style={{ marginBottom: 18 }}>
              <label
                style={{
                  display: "block",
                  fontSize: 10,
                  letterSpacing: 2,
                  textTransform: "uppercase",
                  color: T.muted,
                  marginBottom: 10,
                }}
              >
                Experience level{" "}
                <span style={{ color: T.muted, opacity: 0.5 }}>(optional)</span>
              </label>
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))",
                  gap: 8,
                }}
              >
                {experiences.map((exp) => {
                  const selected = form.experience === exp;
                  return (
                    <button
                      key={exp}
                      type="button"
                      onClick={() => update("experience", selected ? "" : exp)}
                      style={{
                        padding: "10px 12px",
                        background: selected
                          ? "rgba(139,92,246,0.08)"
                          : "rgba(255,255,255,0.02)",
                        border: `1px solid ${selected ? T.purple : T.border}`,
                        borderRadius: 2,
                        color: selected ? T.white : T.steel,
                        cursor: "pointer",
                        fontFamily: "'Outfit',sans-serif",
                        fontSize: 11,
                        letterSpacing: 1,
                        transition: "all 0.25s",
                      }}
                    >
                      {exp}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Optional message */}
            <div style={{ marginBottom: 20 }}>
              <label
                style={{
                  display: "block",
                  fontSize: 10,
                  letterSpacing: 2,
                  textTransform: "uppercase",
                  color: T.muted,
                  marginBottom: 8,
                }}
              >
                Anything else?{" "}
                <span style={{ color: T.muted, opacity: 0.5 }}>(optional)</span>
              </label>
              <textarea
                placeholder="Goals, questions, or specific asks..."
                value={form.message}
                onChange={(e) => update("message", e.target.value)}
                onFocus={() => setFocused("message")}
                onBlur={() => setFocused("")}
                rows={3}
                style={{
                  ...inputStyle("message"),
                  resize: "vertical",
                  minHeight: 80,
                  fontFamily: "'Outfit',sans-serif",
                }}
              />
            </div>

            {error && (
              <div
                style={{
                  marginBottom: 16,
                  padding: "10px 14px",
                  background: "rgba(239,68,68,0.08)",
                  border: "1px solid rgba(239,68,68,0.3)",
                  borderRadius: 2,
                  color: "#f87171",
                  fontSize: 12,
                }}
              >
                ⚠ {error}
              </div>
            )}

            <button
              onClick={handleSubmit}
              disabled={loading}
              style={{
                width: "100%",
                padding: "16px",
                border: "none",
                borderRadius: 2,
                cursor: loading ? "wait" : "pointer",
                background: T.gradient,
                color: T.white,
                fontSize: 13,
                fontWeight: 600,
                letterSpacing: 2,
                textTransform: "uppercase",
                fontFamily: "'Outfit',sans-serif",
                opacity: loading ? 0.7 : 1,
                transition: "all 0.3s",
                boxShadow: `0 4px 20px ${T.purpleGlow}`,
              }}
            >
              {loading ? "Submitting..." : "Join the Waitlist →"}
            </button>
            <p
              style={{
                fontSize: 11,
                color: T.muted,
                marginTop: 14,
                textAlign: "center",
                lineHeight: 1.6,
              }}
            >
              No spam. I'll personally reach out with next steps on your chosen
              program.
            </p>
          </div>
        ) : (
          <div
            style={{
              background: T.bgCard,
              border: `1px solid ${T.green}`,
              borderRadius: 4,
              padding: "44px 36px",
              textAlign: "center",
              boxShadow: `0 0 40px rgba(34,197,94,0.12)`,
            }}
          >
            <div
              style={{
                width: 60,
                height: 60,
                margin: "0 auto 20px",
                borderRadius: "50%",
                background: "rgba(34,197,94,0.1)",
                border: `1px solid ${T.green}`,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <svg
                width="28"
                height="28"
                viewBox="0 0 24 24"
                fill="none"
                stroke={T.green}
                strokeWidth="2.5"
                strokeLinecap="round"
                strokeLinejoin="round"
              >
                <polyline points="20 6 9 17 4 12" />
              </svg>
            </div>
            <h3
              style={{
                fontFamily: "'Bebas Neue',sans-serif",
                fontSize: 32,
                letterSpacing: 3,
                color: T.green,
                marginBottom: 14,
              }}
            >
              YOU'RE IN
            </h3>
            <p
              style={{
                fontSize: 14,
                color: T.steel,
                lineHeight: 1.8,
                maxWidth: 420,
                margin: "0 auto 20px",
              }}
            >
              Thanks for signing up. I received your interest in{" "}
              <span style={{ color: T.purple, fontWeight: 600 }}>
                {form.product}
              </span>{" "}
              and will personally reach out to{" "}
              <span style={{ color: T.white }}>{form.email}</span> soon.
            </p>
            <p style={{ fontSize: 12, color: T.muted, lineHeight: 1.7 }}>
              In the meantime →{" "}
              <a
                href="https://www.youtube.com/@letsgocosplay"
                target="_blank"
                rel="noopener noreferrer"
                style={{
                  color: T.purple,
                  textDecoration: "none",
                  fontWeight: 500,
                }}
              >
                @letsgocosplay on YouTube
              </a>
            </p>
          </div>
        )}
      </div>
    </Section>
  );
}

// ─── FAQ ───
function FAQ() {
  const [openIdx, setOpenIdx] = useState(-1);
  const faqs = [
    {
      q: "What is the Toji Physique Protocol?",
      a: "A 4-week, 6-day training program designed for building a lean, dense, athletic physique. It includes full strength and hypertrophy training with detailed sets, reps, rest, tempo, RPE targets, coaching cues, and substitutions for every exercise.",
    },
    {
      q: "Who is this program for?",
      a: "Anyone intermediate or above who wants a structured, aesthetic-focused training system. You should have at least 6 months of gym experience and know basic compound lifts.",
    },
    {
      q: "What format is the program in?",
      a: "You'll access the full program digitally through this website. Each day is mapped out in a clean, readable format — like a premium training spreadsheet, but better.",
    },
    {
      q: "Are exercise substitutions included?",
      a: "Yes. Every main exercise has a listed substitute so you can adapt based on your equipment, mobility, or preference without breaking the system.",
    },
    {
      q: "Will more programs be released?",
      a: "Yes. This is just the first protocol. More programs with different splits, goals, and themes are coming.",
    },
    {
      q: "How do I get notified when it launches?",
      a: "Join the waitlist above. You'll receive one email when the program is live and ready to access.",
    },
  ];

  return (
    <Section id="faq">
      <Heading tag="FAQ" title="FREQUENTLY ASKED" subtitle="Quick answers." />
      <div style={{ maxWidth: 680, margin: "0 auto" }}>
        {faqs.map((f, i) => {
          const open = openIdx === i;
          return (
            <div
              key={i}
              style={{
                borderBottom: `1px solid ${T.border}`,
                cursor: "pointer",
              }}
              onClick={() => setOpenIdx(open ? -1 : i)}
            >
              <div
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                  padding: "18px 0",
                }}
              >
                <span
                  style={{
                    fontSize: 14,
                    fontWeight: 500,
                    color: open ? T.purple : T.white,
                    transition: "color 0.3s",
                    paddingRight: 16,
                  }}
                >
                  {f.q}
                </span>
                <span
                  style={{
                    fontSize: 18,
                    color: T.purple,
                    transition: "transform 0.3s",
                    transform: open ? "rotate(45deg)" : "rotate(0)",
                    flexShrink: 0,
                  }}
                >
                  +
                </span>
              </div>
              <div
                style={{
                  maxHeight: open ? 200 : 0,
                  overflow: "hidden",
                  transition: "max-height 0.4s ease",
                }}
              >
                <p
                  style={{
                    fontSize: 13,
                    color: T.muted,
                    lineHeight: 1.8,
                    paddingBottom: 18,
                  }}
                >
                  {f.a}
                </p>
              </div>
            </div>
          );
        })}
      </div>
    </Section>
  );
}

